import csv


def load_orders(path):
    with open(path, newline='', encoding='utf-8') as fh:
        return list(csv.DictReader(fh))


def summarize_orders(rows):
    total = 0
    by_region = {}
    for row in rows:
        if row['status'] == 'cancelled':
            continue
        amount = row['amount']
        total += amount
        region = row['region']
        by_region[region] = by_region.get(region, 0) + amount
    return {'count': len(rows), 'total': round(total, 2), 'by_region': by_region}


def filter_shipments(rows):
    return [row for row in rows if row['status'] == 'paid' and row['shipped']]

