from orders.pipeline import load_orders, summarize_orders, filter_shipments


def test_summary_uses_numbers_and_excludes_cancelled():
    rows = load_orders('data/orders.csv')
    assert summarize_orders(rows) == {'count': 3, 'total': 230.75, 'by_region': {'north': 150.75, 'south': 80.0}}


def test_shipments_only_paid_and_shipped_true():
    rows = load_orders('data/orders.csv')
    shipments = filter_shipments(rows)
    assert [row['id'] for row in shipments] == ['A', 'D']
